140	int parse_node(int mode) {
141	    if (parse_err) return 0;
142	
143	    int left;
144	    int ty = tok_type[parse_pos];
145	
146	    // -- Parse a value --
147	
148	    if (ty == TOK_NUM) {
149	        left = ast_num(tok_val[parse_pos]);
150	        parse_pos++;
151	
152	        // Stranding: adjacent numbers form a vector (e.g. 1 2 3)
153	        if (tok_type[parse_pos] == TOK_NUM) {
154	            strand_buf[0] = node_val[left];
155	            int count = 1;
156	            while (tok_type[parse_pos] == TOK_NUM && count < 64) {
157	                strand_buf[count] = tok_val[parse_pos];
158	                parse_pos++;
159	                count++;
160	            }
161	            int aidx = arr_vector(count);
162	            if (aidx < 0) { parse_err = 1; return 0; }
163	            int si = 0;
164	            while (si < count) {
165	                arr_set(aidx, si, strand_buf[si]);
166	                si++;
167	            }
168	            left = ast_vec(aidx);
169	        }
170	    } else if (ty == TOK_LPAREN) {
171	        parse_pos++;
172	        left = parse_node(0);
173	        if (parse_err) return 0;
174	        if (tok_type[parse_pos] != TOK_RPAREN) {
175	            parse_err = 1;
176	            return 0;
177	        }
178	        parse_pos++;
179	    } else if (ty == TOK_QLED) {
180	        int n = ast_new();
181	        node_type[n] = NODE_QLED;
182	        left = n;
183	        parse_pos++;
184	    } else if (ty == TOK_QSW) {
185	        int n = ast_new();
186	        node_type[n] = NODE_QSW;
187	        left = n;
188	        parse_pos++;
189	    } else if (ty == TOK_IDENT) {
190	        int sym_idx = sym_lookup(parse_line, tok_val[parse_pos]);
191	        if (sym_idx < 0) { parse_err = 1; return 0; }
192	        parse_pos++;
193	        if (tok_type[parse_pos] == TOK_LBRAK) {
194	            // IDENT[expr] -- shared variable indexed read
195	            parse_pos++;
196	            int idx_expr = parse_node(0);
197	            if (parse_err) return 0;
198	            if (tok_type[parse_pos] != TOK_RBRAK) { parse_err = 1; return 0; }
199	            parse_pos++;
200	            int nd = ast_new();
201	            node_type[nd] = NODE_SVO_READ;
202	            node_val[nd] = sym_idx;
203	            node_right[nd] = idx_expr;
204	            left = nd;
205	        } else {
206	            left = ast_ident(sym_idx);
207	        }
208	    } else if (is_binop(ty) && tok_type[parse_pos + 1] == TOK_SLASH) {
209	        // Reduce operator: +/ -/ */ (op followed by slash)
210	        int op = ty;
211	        parse_pos = parse_pos + 2;
212	        int operand = parse_node(0);
213	        if (parse_err) return 0;
214	        left = ast_reduce(op, operand);
215	    } else if (ty == TOK_RES) {
216	        // Monadic primitive function (e.g. iota expr)
217	        int res_id = tok_val[parse_pos];
218	        parse_pos++;
219	        int operand = parse_node(0);
220	        if (parse_err) return 0;
221	        left = ast_monad(res_id, operand);
222	    } else if (ty == TOK_MINUS) {
223	        // Monadic negate: applies to entire right expression (APL rule)
224	        parse_pos++;
225	        int operand = parse_node(0);
226	        if (parse_err) return 0;
227	        left = ast_neg(operand);
228	    } else {
229	        parse_err = 1;
230	        return 0;
231	    }
232	
233	    // -- If mode 0 (expr) and next is binop or dyadic reserved, parse right --
234	
235	    if (mode == 0 && is_binop(tok_type[parse_pos])) {
236	        int op = tok_type[parse_pos];
237	        parse_pos++;
238	        int right = parse_node(0);
239	        if (parse_err) return 0;
240	        return ast_binop(op, left, right);
241	    }
242	
243	    if (mode == 0 && tok_type[parse_pos] == TOK_RES && is_dyadic_res(tok_val[parse_pos])) {
244	        int res_id = tok_val[parse_pos];
245	        parse_pos++;
246	        int right = parse_node(0);
247	        if (parse_err) return 0;
248	        return ast_dyad(res_id, left, right);
249	    }
250	
251	    // Shared variable offer: IDENT qsvo EXPR
252	    if (mode == 0 && tok_type[parse_pos] == TOK_QSVO && node_type[left] == NODE_IDENT) {
253	        int sym_idx = node_val[left];
254	        parse_pos++;
255	        int right = parse_node(0);
256	        if (parse_err) return 0;
257	        int n = ast_new();
258	        node_type[n] = NODE_QSVO;
259	        node_val[n] = sym_idx;
260	        node_right[n] = right;
261	        return n;
262	    }
263	
264	    return left;
265	}
