267	// Parse the token stream. Returns root node index, or -1 on error.
268	// line is needed for identifier name resolution into the symbol table.
269	int parse(char *line) {
270	    node_count = 0;
271	    parse_pos = 0;
272	    parse_err = 0;
273	    parse_line = line;
274	
275	    // Check for qled assignment: qled <- expr
276	    if (tok_type[0] == TOK_QLED && tok_type[1] == TOK_ASSIGN) {
277	        parse_pos = 2;
278	        int expr = parse_node(0);
279	        if (parse_err) return -1;
280	        if (tok_type[parse_pos] != TOK_EOL) return -1;
281	        int n = ast_new();
282	        node_type[n] = NODE_QLED_ASSIGN;
283	        node_right[n] = expr;
284	        return n;
285	    }
286	
287	    // Check for qsw assignment: qsw is read-only, reject with SYNTAX ERROR
288	    if (tok_type[0] == TOK_QSW && tok_type[1] == TOK_ASSIGN) {
289	        return -1;
290	    }
291	
292	    // Check for quad output: [] <- expr (IBM 5100 convention)
293	    if (tok_type[0] == TOK_QUAD && tok_type[1] == TOK_ASSIGN) {
294	        parse_pos = 2;
295	        int expr = parse_node(0);
296	        if (parse_err) return -1;
297	        if (tok_type[parse_pos] != TOK_EOL) return -1;
298	        int n = ast_new();
299	        node_type[n] = NODE_QOUT;
300	        node_right[n] = expr;
301	        return n;
302	    }
303	
304	    // Check for shared variable indexed write: IDENT[expr] <- expr
305	    if (tok_type[0] == TOK_IDENT && tok_type[1] == TOK_LBRAK) {
306	        int sym_idx = sym_lookup(line, tok_val[0]);
307	        if (sym_idx < 0) { return -1; }
308	        parse_pos = 2;
309	        int idx_expr = parse_node(0);
310	        if (parse_err) return -1;
311	        if (tok_type[parse_pos] != TOK_RBRAK) { parse_err = 1; return -1; }
312	        parse_pos++;
313	        if (tok_type[parse_pos] == TOK_ASSIGN) {
314	            // IDENT[expr] <- expr (indexed write)
315	            parse_pos++;
316	            int val_expr = parse_node(0);
317	            if (parse_err) return -1;
318	            if (tok_type[parse_pos] != TOK_EOL) return -1;
319	            int n = ast_new();
320	            node_type[n] = NODE_SVO_WRITE;
321	            node_val[n] = sym_idx;
322	            node_left[n] = idx_expr;
323	            node_right[n] = val_expr;
324	            return n;
325	        }
326	        if (tok_type[parse_pos] != TOK_EOL) {
327	            // IDENT[expr] followed by more (could be in expression context)
328	            // For now, only standalone read supported at top level
329	            // Fall through to expression parsing below
330	            parse_pos = 0;
331	            node_count = 0;
332	            parse_err = 0;
333	        } else {
334	            // IDENT[expr] standalone read
335	            int n = ast_new();
336	            node_type[n] = NODE_SVO_READ;
337	            node_val[n] = sym_idx;
338	            node_right[n] = idx_expr;
339	            return n;
340	        }
341	    }
342	
343	    // Check for assignment: IDENT <- expr
344	    if (tok_type[0] == TOK_IDENT && tok_type[1] == TOK_ASSIGN) {
345	        int sym_idx = sym_lookup(line, tok_val[0]);
346	        if (sym_idx < 0) { return -1; }
347	        parse_pos = 2;
348	        int expr = parse_node(0);
349	        if (parse_err) return -1;
350	        if (tok_type[parse_pos] != TOK_EOL) return -1;
351	        return ast_assign(sym_idx, expr);
352	    }
353	
354	    int root = parse_node(0);
355	
356	    if (!parse_err && tok_type[parse_pos] != TOK_EOL) {
357	        parse_err = 1;
358	    }
359	
360	    if (parse_err) return -1;
361	    return root;
362	}
