    return i;  // return length of match (0 = no match since word is non-empty)
}

// Check if character is a lowercase letter (a-z)
int is_lower(int ch) {
    return ch >= 97 && ch <= 122;
}

// Check if character is an uppercase letter (A-Z)
int is_upper(int ch) {
    return ch >= 65 && ch <= 90;
}

// Check if character is a digit (0-9)
int is_digit(int ch) {
    return ch >= 48 && ch <= 57;
}

// Check if character is alphanumeric or underscore
int is_alnum(int ch) {
    return is_lower(ch) || is_upper(ch) || is_digit(ch);
}

// ---- Reserved word lookup ----
// Returns reserved word ID if the lowercase word starting at pos matches,
// or -1 if not a reserved word. Sets *end to position past the word.
int lookup_reserved(char *src, int pos, int *end) {
    int len;

    len = str_match(src, pos, "rho");
    if (len == 3 && !is_alnum(src[pos + 3])) { *end = pos + 3; return RES_RHO; }

    len = str_match(src, pos, "iota");
    if (len == 4 && !is_alnum(src[pos + 4])) { *end = pos + 4; return RES_IOTA; }

    len = str_match(src, pos, "take");
    if (len == 4 && !is_alnum(src[pos + 4])) { *end = pos + 4; return RES_TAKE; }

    len = str_match(src, pos, "drop");
    if (len == 4 && !is_alnum(src[pos + 4])) { *end = pos + 4; return RES_DROP; }

    len = str_match(src, pos, "rev");
    if (len == 3 && !is_alnum(src[pos + 3])) { *end = pos + 3; return RES_REV; }

    len = str_match(src, pos, "cat");
    if (len == 3 && !is_alnum(src[pos + 3])) { *end = pos + 3; return RES_CAT; }

    len = str_match(src, pos, "and");
    if (len == 3 && !is_alnum(src[pos + 3])) { *end = pos + 3; return RES_AND; }

    len = str_match(src, pos, "or");
    if (len == 2 && !is_alnum(src[pos + 2])) { *end = pos + 2; return RES_OR; }

    len = str_match(src, pos, "not");
    if (len == 3 && !is_alnum(src[pos + 3])) { *end = pos + 3; return RES_NOT; }

    return -1;
}

// ---- Tokenizer ----
// Tokenize input line into tok_type/tok_val/tok_pos arrays.
// Returns number of tokens (also stored in tok_count).
// On error, returns -1 (unrecognized character).
int tokenize(char *line) {
    int i = 0;
    int t = 0;

    while (line[i] && t < TOK_MAX - 1) {
        // Skip whitespace
        if (line[i] == 32) {
            i++;
            continue;
        }

        // Number: digits, or underscore followed by digit (APL negative)
        if (is_digit(line[i]) || (line[i] == 95 && is_digit(line[i + 1]))) {
            tok_type[t] = TOK_NUM;
            tok_pos[t] = i;
            int end;
            tok_val[t] = parse_int(line, i, &end);
            i = end;
            t++;
            continue;
        }

        // Lowercase letter: quad variables, reserved word, or unknown
        if (is_lower(line[i])) {
            // Check for quad variables first
            int len;
            len = str_match(line, i, "qled");
            if (len == 4 && !is_alnum(line[i + 4])) {
                tok_type[t] = TOK_QLED;
                tok_pos[t] = i;
                tok_val[t] = 0;
                t++;
                i = i + 4;
                continue;
            }

            len = str_match(line, i, "qsw");
            if (len == 3 && !is_alnum(line[i + 3])) {
                tok_type[t] = TOK_QSW;
                tok_pos[t] = i;
                tok_val[t] = 0;
                t++;
                i = i + 3;
                continue;
            }

            len = str_match(line, i, "qsvo");
            if (len == 4 && !is_alnum(line[i + 4])) {
                tok_type[t] = TOK_QSVO;
                tok_pos[t] = i;
                tok_val[t] = 0;
                t++;
                i = i + 4;
                continue;
            }

            int end;
            int res = lookup_reserved(line, i, &end);
            if (res >= 0) {
                tok_type[t] = TOK_RES;
                tok_val[t] = res;
                tok_pos[t] = i;
                i = end;
                t++;
                continue;
            }
            // Unknown lowercase word -- error
            return -1;
        }

        // Uppercase letter: user identifier
        if (is_upper(line[i])) {
            tok_type[t] = TOK_IDENT;
            tok_pos[t] = i;
            tok_val[t] = i;  // store start position for name extraction
            i++;
            while (is_alnum(line[i])) i++;
            t++;
            continue;
        }

        // Operators and punctuation
        if (line[i] == 43) { tok_type[t] = TOK_PLUS;   tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
        if (line[i] == 45) { tok_type[t] = TOK_MINUS;  tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
        if (line[i] == 42) { tok_type[t] = TOK_STAR;   tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
        if (line[i] == 47) { tok_type[t] = TOK_SLASH;  tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
        if (line[i] == 40) { tok_type[t] = TOK_LPAREN; tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
        if (line[i] == 41) { tok_type[t] = TOK_RPAREN; tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }

        // Quad: [] (IBM 5100 ASCII convention for ⎕) or bracket indexing [expr]
        if (line[i] == 91) {
            if (line[i + 1] == 93) {
                // [] = quad
                tok_type[t] = TOK_QUAD;
                tok_pos[t] = i;
                tok_val[t] = 0;
                t++;
                i = i + 2;
            } else {
                // [ = bracket index open
                tok_type[t] = TOK_LBRAK;
                tok_pos[t] = i;
                tok_val[t] = 0;
                t++;
                i++;
            }
            continue;
        }
        if (line[i] == 93) {
            tok_type[t] = TOK_RBRAK;
            tok_pos[t] = i;
            tok_val[t] = 0;
            t++;
            i++;
            continue;
        }

        // Assignment: <-
        if (line[i] == 60 && line[i + 1] == 45) {
            tok_type[t] = TOK_ASSIGN;
            tok_pos[t] = i;
            tok_val[t] = 0;
            t++;
            i = i + 2;
            continue;
        }

        // Unrecognized character
        return -1;
    }

    // Append EOL sentinel
    tok_type[t] = TOK_EOL;
    tok_pos[t] = i;
    tok_val[t] = 0;
    t++;
    tok_count = t;
    return t;
}

// ---- Debug: print token list ----
// Useful for testing the tokenizer in isolation.
void tok_dump(char *line) {
    int i = 0;
    while (i < tok_count) {
        int ty = tok_type[i];
        if (ty == TOK_EOL) {
            io_print("EOL");
        } else if (ty == TOK_NUM) {
            io_print("NUM:");
            print_int(tok_val[i]);
        } else if (ty == TOK_IDENT) {
            io_print("ID:");
            int p = tok_val[i];
            while (is_alnum(line[p])) {
                putchar(line[p]);
                p++;
            }
        } else if (ty == TOK_RES) {
            io_print("RES:");
            int r = tok_val[i];
            if (r == RES_RHO)  io_print("rho");
            if (r == RES_IOTA) io_print("iota");
            if (r == RES_TAKE) io_print("take");
            if (r == RES_DROP) io_print("drop");
            if (r == RES_REV)  io_print("rev");
            if (r == RES_CAT)  io_print("cat");
        } else if (ty == TOK_PLUS)   { putchar(43); }
          else if (ty == TOK_MINUS)  { putchar(45); }
          else if (ty == TOK_STAR)   { putchar(42); }
          else if (ty == TOK_SLASH)  { putchar(47); }
          else if (ty == TOK_LPAREN) { putchar(40); }
          else if (ty == TOK_RPAREN) { putchar(41); }
          else if (ty == TOK_ASSIGN) { io_print("<-"); }

        if (tok_type[i + 1] != TOK_EOL || ty == TOK_EOL) {
            // nothing
        }
        if (i + 1 < tok_count) putchar(32);
        i++;
    }
    putchar(10);
}

// COR24 APL Interpreter -- Parser
// Right-to-left recursive descent with vector literal stranding.
// APL: all operators equal precedence, right-associative.
// 2 + 3 * 4  ->  2 + (3 * 4)  ->  14
// 1 2 3      ->  3-element vector (adjacent numbers strand)

#pragma once

// AST node types
#define NODE_NUM    0   // integer literal (val = value)
#define NODE_BINOP  1   // binary op (val = operator tok type)
#define NODE_NEG    2   // monadic negate (right = operand)
#define NODE_IDENT  3   // variable reference (val = symbol index)
#define NODE_ASSIGN 4   // assignment (val = symbol index, right = expr)
#define NODE_VEC    5   // vector literal (val = heap array index)
#define NODE_MONAD  6   // monadic primitive (val = RES_xxx, right = operand)
#define NODE_DYAD   7   // dyadic primitive (val = RES_xxx, left/right = args)
#define NODE_REDUCE 8   // reduce operator (val = op tok type, right = operand)
#define NODE_QOUT   9   // quad output (right = expr to print)
#define NODE_QLED  10   // qled read (no children)
#define NODE_QLED_ASSIGN 11  // qled <- expr (right = expr)
#define NODE_QSW   12   // qsw read (no children, read-only)
#define NODE_QSVO  13   // shared variable offer (val = sym index, right = AP expr)
#define NODE_SVO_READ  14   // shared var indexed read (val = sym index, right = index expr)
#define NODE_SVO_WRITE 15  // shared var indexed write (val = sym index, left = index, right = value)

#define AST_MAX 64

// AST storage (parallel arrays)
int node_type[AST_MAX];
int node_val[AST_MAX];
int node_left[AST_MAX];
int node_right[AST_MAX];
int node_count;

// Parser state
int parse_pos;
int parse_err;
char *parse_line;   // source line for identifier lookup

// Allocate a new AST node
int ast_new() {
    if (node_count >= AST_MAX) {
        parse_err = 1;
        return 0;
    }
    int n = node_count;
    node_count++;
    node_left[n] = -1;
    node_right[n] = -1;
    return n;
}

int ast_num(int val) {
    int n = ast_new();
    node_type[n] = NODE_NUM;
    node_val[n] = val;
    return n;
}

int ast_binop(int op, int left, int right) {
    int n = ast_new();
    node_type[n] = NODE_BINOP;
    node_val[n] = op;
    node_left[n] = left;
    node_right[n] = right;
    return n;
}

int ast_neg(int operand) {
    int n = ast_new();
    node_type[n] = NODE_NEG;
    node_right[n] = operand;
    return n;
}

int ast_ident(int sym_idx) {
    int n = ast_new();
    node_type[n] = NODE_IDENT;
    node_val[n] = sym_idx;
    return n;
}

int ast_assign(int sym_idx, int expr) {
    int n = ast_new();
    node_type[n] = NODE_ASSIGN;
    node_val[n] = sym_idx;
    node_right[n] = expr;
    return n;
}

int ast_vec(int heap_idx) {
    int n = ast_new();
    node_type[n] = NODE_VEC;
    node_val[n] = heap_idx;
    return n;
}

int ast_monad(int res_id, int operand) {
    int n = ast_new();
    node_type[n] = NODE_MONAD;
    node_val[n] = res_id;
    node_right[n] = operand;
    return n;
}

int ast_dyad(int res_id, int left, int right) {
    int n = ast_new();
    node_type[n] = NODE_DYAD;
    node_val[n] = res_id;
    node_left[n] = left;
    node_right[n] = right;
    return n;
}

int ast_reduce(int op, int operand) {
    int n = ast_new();
    node_type[n] = NODE_REDUCE;
    node_val[n] = op;
    node_right[n] = operand;
    return n;
}

// Check if a reserved word can be used dyadically
int is_dyadic_res(int res_id) {
    return res_id == RES_RHO || res_id == RES_TAKE || res_id == RES_DROP || res_id == RES_CAT || res_id == RES_AND || res_id == RES_OR;
}

// Temporary buffer for collecting strand elements
int strand_buf[64];

int is_binop(int ty) {
    return ty == TOK_PLUS || ty == TOK_MINUS || ty == TOK_STAR || ty == TOK_SLASH;
}

// Combined parse function avoids mutual recursion.
// mode 0 = expression, mode 1 = value only
int parse_node(int mode);

int parse_node(int mode) {
    if (parse_err) return 0;

    int left;
    int ty = tok_type[parse_pos];

    // -- Parse a value --

    if (ty == TOK_NUM) {
        left = ast_num(tok_val[parse_pos]);
        parse_pos++;

        // Stranding: adjacent numbers form a vector (e.g. 1 2 3)
        if (tok_type[parse_pos] == TOK_NUM) {
            strand_buf[0] = node_val[left];
            int count = 1;
            while (tok_type[parse_pos] == TOK_NUM && count < 64) {
                strand_buf[count] = tok_val[parse_pos];
                parse_pos++;
                count++;
            }
            int aidx = arr_vector(count);
            if (aidx < 0) { parse_err = 1; return 0; }
            int si = 0;
            while (si < count) {
                arr_set(aidx, si, strand_buf[si]);
                si++;
            }
            left = ast_vec(aidx);
        }
    } else if (ty == TOK_LPAREN) {
        parse_pos++;
        left = parse_node(0);
        if (parse_err) return 0;
        if (tok_type[parse_pos] != TOK_RPAREN) {
            parse_err = 1;
            return 0;
        }
        parse_pos++;
    } else if (ty == TOK_QLED) {
        int n = ast_new();
        node_type[n] = NODE_QLED;
        left = n;
        parse_pos++;
    } else if (ty == TOK_QSW) {
        int n = ast_new();
        node_type[n] = NODE_QSW;
        left = n;
        parse_pos++;
    } else if (ty == TOK_IDENT) {
        int sym_idx = sym_lookup(parse_line, tok_val[parse_pos]);
        if (sym_idx < 0) { parse_err = 1; return 0; }
        parse_pos++;
        if (tok_type[parse_pos] == TOK_LBRAK) {
            // IDENT[expr] -- shared variable indexed read
            parse_pos++;
            int idx_expr = parse_node(0);
            if (parse_err) return 0;
            if (tok_type[parse_pos] != TOK_RBRAK) { parse_err = 1; return 0; }
            parse_pos++;
            int nd = ast_new();
            node_type[nd] = NODE_SVO_READ;
            node_val[nd] = sym_idx;
            node_right[nd] = idx_expr;
            left = nd;
        } else {
            left = ast_ident(sym_idx);
        }
    } else if (is_binop(ty) && tok_type[parse_pos + 1] == TOK_SLASH) {
        // Reduce operator: +/ -/ */ (op followed by slash)
        int op = ty;
        parse_pos = parse_pos + 2;
        int operand = parse_node(0);
        if (parse_err) return 0;
        left = ast_reduce(op, operand);
    } else if (ty == TOK_RES) {
        // Monadic primitive function (e.g. iota expr)
        int res_id = tok_val[parse_pos];
        parse_pos++;
        int operand = parse_node(0);
        if (parse_err) return 0;
        left = ast_monad(res_id, operand);
    } else if (ty == TOK_MINUS) {
        // Monadic negate: applies to entire right expression (APL rule)
        parse_pos++;
        int operand = parse_node(0);
        if (parse_err) return 0;
        left = ast_neg(operand);
    } else {
        parse_err = 1;
        return 0;
    }

    // -- If mode 0 (expr) and next is binop or dyadic reserved, parse right --

    if (mode == 0 && is_binop(tok_type[parse_pos])) {
        int op = tok_type[parse_pos];
        parse_pos++;
        int right = parse_node(0);
        if (parse_err) return 0;
        return ast_binop(op, left, right);
    }

    if (mode == 0 && tok_type[parse_pos] == TOK_RES && is_dyadic_res(tok_val[parse_pos])) {
        int res_id = tok_val[parse_pos];
        parse_pos++;
        int right = parse_node(0);
        if (parse_err) return 0;
        return ast_dyad(res_id, left, right);
    }

    // Shared variable offer: IDENT qsvo EXPR
    if (mode == 0 && tok_type[parse_pos] == TOK_QSVO && node_type[left] == NODE_IDENT) {
        int sym_idx = node_val[left];
        parse_pos++;
        int right = parse_node(0);
        if (parse_err) return 0;
        int n = ast_new();
        node_type[n] = NODE_QSVO;
        node_val[n] = sym_idx;
        node_right[n] = right;
        return n;
    }

    return left;
}

// Parse the token stream. Returns root node index, or -1 on error.
// line is needed for identifier name resolution into the symbol table.
int parse(char *line) {
    node_count = 0;
    parse_pos = 0;
    parse_err = 0;
    parse_line = line;

    // Check for qled assignment: qled <- expr
    if (tok_type[0] == TOK_QLED && tok_type[1] == TOK_ASSIGN) {
        parse_pos = 2;
        int expr = parse_node(0);
        if (parse_err) return -1;
        if (tok_type[parse_pos] != TOK_EOL) return -1;
        int n = ast_new();
        node_type[n] = NODE_QLED_ASSIGN;
        node_right[n] = expr;
        return n;
    }

    // Check for qsw assignment: qsw is read-only, reject with SYNTAX ERROR
    if (tok_type[0] == TOK_QSW && tok_type[1] == TOK_ASSIGN) {
        return -1;
    }

    // Check for quad output: [] <- expr (IBM 5100 convention)
    if (tok_type[0] == TOK_QUAD && tok_type[1] == TOK_ASSIGN) {
        parse_pos = 2;
        int expr = parse_node(0);
        if (parse_err) return -1;
        if (tok_type[parse_pos] != TOK_EOL) return -1;
        int n = ast_new();
        node_type[n] = NODE_QOUT;
        node_right[n] = expr;
        return n;
    }

    // Check for shared variable indexed write: IDENT[expr] <- expr
    if (tok_type[0] == TOK_IDENT && tok_type[1] == TOK_LBRAK) {
        int sym_idx = sym_lookup(line, tok_val[0]);
        if (sym_idx < 0) { return -1; }
        parse_pos = 2;
        int idx_expr = parse_node(0);
        if (parse_err) return -1;
        if (tok_type[parse_pos] != TOK_RBRAK) { parse_err = 1; return -1; }
        parse_pos++;
        if (tok_type[parse_pos] == TOK_ASSIGN) {
            // IDENT[expr] <- expr (indexed write)
            parse_pos++;
            int val_expr = parse_node(0);
            if (parse_err) return -1;
            if (tok_type[parse_pos] != TOK_EOL) return -1;
            int n = ast_new();
            node_type[n] = NODE_SVO_WRITE;
            node_val[n] = sym_idx;
            node_left[n] = idx_expr;
            node_right[n] = val_expr;
            return n;
        }
        if (tok_type[parse_pos] != TOK_EOL) {
            // IDENT[expr] followed by more (could be in expression context)
            // For now, only standalone read supported at top level
            // Fall through to expression parsing below
            parse_pos = 0;
            node_count = 0;
            parse_err = 0;
        } else {
            // IDENT[expr] standalone read
            int n = ast_new();
            node_type[n] = NODE_SVO_READ;
            node_val[n] = sym_idx;
            node_right[n] = idx_expr;
            return n;
        }
    }

    // Check for assignment: IDENT <- expr
    if (tok_type[0] == TOK_IDENT && tok_type[1] == TOK_ASSIGN) {
        int sym_idx = sym_lookup(line, tok_val[0]);
        if (sym_idx < 0) { return -1; }
        parse_pos = 2;
        int expr = parse_node(0);
        if (parse_err) return -1;
        if (tok_type[parse_pos] != TOK_EOL) return -1;
        return ast_assign(sym_idx, expr);
    }

    int root = parse_node(0);

    if (!parse_err && tok_type[parse_pos] != TOK_EOL) {
        parse_err = 1;
    }

    if (parse_err) return -1;
    return root;
}

// Debug: dump AST with full parenthesization
void ast_dump(int n) {
    if (n < 0 || n >= node_count) return;

    int ty = node_type[n];
    if (ty == NODE_NUM) {
        print_int(node_val[n]);
    } else if (ty == NODE_BINOP) {
        putchar(40);
        ast_dump(node_left[n]);
        putchar(32);
        if (node_val[n] == TOK_PLUS)  putchar(43);
        if (node_val[n] == TOK_MINUS) putchar(45);
        if (node_val[n] == TOK_STAR)  putchar(42);
        if (node_val[n] == TOK_SLASH) putchar(47);
        putchar(32);
        ast_dump(node_right[n]);
        putchar(41);
    } else if (ty == NODE_NEG) {
        putchar(40);
        putchar(45);
        ast_dump(node_right[n]);
        putchar(41);
    }
}

